var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 제 9 포격전대 메이즈\\n업무 보고","JPN":"管理局第9砲撃戦隊メイズ\\n業務報告","ENG":"[[","TWN":"管理局第9砲擊戰隊 梅茲\\n報告任務中","SCN":"管理局第9炮击战队梅兹\\n工作汇报","DEU":"Die 9.\xA0Artilleriedivision der Administration Maze\\nBerichterstattung","FRA":"Maze, 9e\xA0division d'artillerie de l'Administration\\nRapport de travail"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"슬슬 업무 보고 시간이네. 류드밀라도 지금쯤이면 돌아왔으려나.","JPN":"そろそろ業務報告の時間ね。リュドミラも戻っている頃かしら。","ENG":"It's almost time to report back to Lyudmila. I wonder if she's back.","TWN":"快到報告任務的時間了，盧德米拉不知道回來了沒？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"응? 기타 소리……?","JPN":"うん？　ギターの音……？","ENG":"Hmm? Guitar sounds...?","TWN":"嗯？吉他聲……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"부, 부전대장님? 언제 오셨습니까?","JPN":"ふ、副戦隊長殿？　いつからいらっしゃったんですか？","ENG":"D-Deputy Commander? How long were you standing there?","TWN":"副，副戰隊長？你什麼時候來的？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"놀라게 했다면 미안해. 몰래 감상만 하려고 했는데.","JPN":"驚かせてしまってごめんなさい。こっそり聴くだけにしようと思っていたんだけれど。","ENG":"Sorry if I startled you. I was going to listen quietly so you wouldn't notice.","TWN":"抱歉嚇到你，我本來只是想默默欣賞而已。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"처음 들어보는 멜로디네. 발레리 네가 직접 지은 거니?","JPN":"そのメロディーは初めて聞くわ。ヴァレリーが自分で書いたの？","ENG":"I've never heard that melody before. Did you come up with it, Valeriy?","TWN":"沒聽過的旋律呢？是你自己做的嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"하하, 그렇게 대단한 건 아니고 손 가는 대로 쳐 본 겁니다.","JPN":"はは、そんなに大層なものじゃないですよ、なんとなく気の向くまま弾いていただけで。","ENG":"Hah hah, it's nothing great. I was just improvising.","TWN":"哈哈，沒這麼厲害啦，只是隨手彈彈而已。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"멋진 곡이 될 것 같아. 나중에 완성되면 꼭 들려줘.","JPN":"素敵な曲になりそうね。完成したらぜひ聞かせてちょうだい。","ENG":"I think it'll turn out to be a great song. Play it for me when it's done.","TWN":"感覺會是一首很棒的曲子，完成後要彈給我聽喔。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"당연히 제일 먼저 들려드려야죠! 염려 붙들어 매십시오!","JPN":"もちろん一番最初にお聞かせします！　ご心配なく！","ENG":"Of course! You'll be the first to hear it! I promise!","TWN":"當然第一個就要彈給副戰隊長聽！放一百萬個心吧！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 고마워, 발레리.","JPN":"ふふっ、ありがとう。ヴァレリー。","ENG":"Haha. Thanks, Valeriy.","TWN":"呵呵，謝啦，瓦萊里。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"오늘은 평소보다 일찍 왔네. 고생했어, 류드밀라.","JPN":"今日はいつもより早かったわね。お疲れ様、リュドミラ。","ENG":"You're back earlier than usual. You must be exhausted, Lyudmila.","TWN":"你今天來得比較早呢，辛苦囉，盧德米拉。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"부대 일을 전부 맡겨 놓고 간 입장에서 들을 말은 아니군.","JPN":"部隊の仕事を全部君に放り投げて行った身としては、そう言ってもらえる資格はないと思うが。","ENG":"I don't think I can complain after leaving you to manage the division.","TWN":"我把部隊的事都交給你，我有什麼好辛苦的。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하필 훈련이 있는 날 자리를 비우다니… 전대장으로서 면목이 없다.","JPN":"よりによって訓練がある日に席を外すなんて……戦隊長として面目ない。","ENG":"Having to leave on training day... I am ashamed to be called your commander.","TWN":"而且偏偏還是在訓練的時候…身為戰隊長實在是非常羞愧。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아. 위에서 부르는데 당연히 다녀와야지.","JPN":"大丈夫よ。上部から呼び出しがあったんだから、行くのが当然でしょう。","ENG":"It's all right. You gotta go when your superior calls you.","TWN":"沒事，既然是上頭的吩咐，你當然要去一趟囉。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내가 자리를 비운 동안 부대에 별일 없었나?","JPN":"私がいない間部隊には何もなかったか？","ENG":"Did anything particular happen while I was away?","TWN":"我不在的這段時間，隊上沒什麼事吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음. 소소한 것 몇 가지 정도.","JPN":"うーん、些細なことならいくつか。","ENG":"Hmm... Just a few trivial things.","TWN":"嗯，都是些小事。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"며칠 전에 새로 온 아이가 폭발물을 잘못 건드려서 격납고 차단벽이 파손됐어.","JPN":"数日前、新しく入ってきた子がうっかり爆発物を爆発させてしまって、格納庫のシャッターが破損したわ。","ENG":"The rookie who joined a few days ago mishandled the explosives, destroying the hangar's shutter door.","TWN":"幾天前新來的孩子不小心誤觸炸彈，結果炸毀機艙的隔間。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"폭발물을 취급할 만한 부대원이라면…… 다닐이? 생명에 지장은 없나?","JPN":"爆発物を取り扱える部隊員といえば……ダニールか？　命に別状は？","ENG":"Someone who would be handling the explosives is... Danil? Is he all right?","TWN":"可以碰到炸彈的隊員……是丹尼爾？他還好嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"일단은 생채기만 생긴 정도야.","JPN":"ひとまず軽い怪我程度で済んだわ。","ENG":"Just a few scratches here and there.","TWN":"就一些皮肉傷。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};